// src/components/WriteModal.jsx
import { useState, useRef } from "react";
import { createPost, uploadImage } from "../firebase/posts";

const CATEGORIES = ["Technology", "Agile", "Design", "Business", "Innovation", "Tutorial"];

export default function WriteModal({ onClose, onPublished, isDemo, onDemoPublish }) {
  const [form, setForm] = useState({
    title: "", author: "", category: "Technology", content: "",
  });
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [uploading, setUploading] = useState(false);
  const [publishing, setPublishing] = useState(false);
  const [errors, setErrors] = useState({});
  const [step, setStep] = useState(1); // 1=form, 2=success
  const fileRef = useRef();

  const set = (k, v) => {
    setForm((f) => ({ ...f, [k]: v }));
    setErrors((e) => ({ ...e, [k]: "" }));
  };

  const validate = () => {
    const errs = {};
    if (!form.title.trim()) errs.title = "Title is required";
    if (!form.author.trim()) errs.author = "Author name is required";
    if (!form.content.trim() || form.content.trim().length < 20)
      errs.content = "Content must be at least 20 characters";
    setErrors(errs);
    return Object.keys(errs).length === 0;
  };

  const handleImage = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!file.type.startsWith("image/")) {
      alert("Please select an image file.");
      return;
    }
    if (file.size > 5 * 1024 * 1024) {
      alert("Image must be under 5MB.");
      return;
    }
    setImageFile(file);
    const reader = new FileReader();
    reader.onload = (ev) => setImagePreview(ev.target.result);
    reader.readAsDataURL(file);
  };

  const handlePublish = async () => {
    if (!validate()) return;
    setPublishing(true);

    try {
      let imageUrl = null;
      let imagePath = null;

      // Upload image to Firebase Storage
      if (imageFile && !isDemo) {
        setUploading(true);
        const result = await uploadImage(imageFile, setUploadProgress);
        imageUrl = result.url;
        imagePath = result.path;
        setUploading(false);
      } else if (imagePreview && isDemo) {
        imageUrl = imagePreview; // use local preview in demo mode
      }

      const postData = {
        title: form.title.trim(),
        author: form.author.trim(),
        category: form.category,
        content: form.content.trim(),
        excerpt: form.content.trim().substring(0, 140) + "…",
        imageUrl,
        imagePath,
      };

      if (isDemo) {
        await new Promise((r) => setTimeout(r, 700));
        onDemoPublish?.(postData);
      } else {
        await createPost(postData);
      }

      setStep(2);
      setTimeout(() => {
        onClose();
        onPublished?.();
      }, 1800);
    } catch (err) {
      console.error(err);
      alert("Failed to publish. Please try again.");
      setPublishing(false);
    }
  };

  const inputStyle = (key) => ({
    ...s.input,
    borderColor: errors[key] ? "var(--red)" : "var(--border)",
  });

  return (
    <div style={s.backdrop} onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div style={s.modal}>

        {/* Close */}
        <button style={s.closeBtn} onClick={onClose}>✕</button>

        {step === 1 ? (
          <>
            {/* Header */}
            <div style={s.header}>
              <div style={s.headerIcon}>✏️</div>
              <div>
                <h2 style={s.title}>Write a New Post</h2>
                <p style={s.subtitle}>
                  {isDemo
                    ? "Demo mode — configure Firebase to persist posts"
                    : "Publish to Firebase in real-time"}
                </p>
              </div>
            </div>

            {/* Form */}
            <div style={s.form}>
              {/* Title */}
              <div style={s.field}>
                <label style={s.label}>Post Title <span style={s.req}>*</span></label>
                <input
                  style={inputStyle("title")}
                  placeholder="An engaging, descriptive title…"
                  value={form.title}
                  onChange={(e) => set("title", e.target.value)}
                />
                {errors.title && <span style={s.error}>{errors.title}</span>}
              </div>

              {/* Row: Author + Category */}
              <div style={s.row}>
                <div style={s.field}>
                  <label style={s.label}>Author <span style={s.req}>*</span></label>
                  <input
                    style={inputStyle("author")}
                    placeholder="Your name"
                    value={form.author}
                    onChange={(e) => set("author", e.target.value)}
                  />
                  {errors.author && <span style={s.error}>{errors.author}</span>}
                </div>
                <div style={s.field}>
                  <label style={s.label}>Category</label>
                  <select
                    style={s.select}
                    value={form.category}
                    onChange={(e) => set("category", e.target.value)}
                  >
                    {CATEGORIES.map((c) => <option key={c}>{c}</option>)}
                  </select>
                </div>
              </div>

              {/* Image Upload */}
              <div style={s.field}>
                <label style={s.label}>
                  Cover Image
                  <span style={s.labelSub}> — stored in Firebase Storage {isDemo && "(demo: local only)"}</span>
                </label>
                <div
                  style={{
                    ...s.uploadZone,
                    borderColor: imagePreview ? "var(--blue)" : "var(--border)",
                    background: imagePreview ? "var(--bg-2)" : "var(--bg)",
                  }}
                  onClick={() => fileRef.current?.click()}
                  onDragOver={(e) => e.preventDefault()}
                  onDrop={(e) => {
                    e.preventDefault();
                    const f = e.dataTransfer.files?.[0];
                    if (f) handleImage({ target: { files: [f] } });
                  }}
                >
                  {imagePreview ? (
                    <div style={s.previewWrap}>
                      <img src={imagePreview} alt="preview" style={s.preview} />
                      <button
                        style={s.removeImg}
                        onClick={(e) => {
                          e.stopPropagation();
                          setImageFile(null);
                          setImagePreview(null);
                        }}
                      >
                        ✕ Remove
                      </button>
                    </div>
                  ) : (
                    <div style={s.uploadPlaceholder}>
                      <span style={{ fontSize: "2rem" }}>🖼️</span>
                      <span style={s.uploadText}>
                        Click or drag to upload
                      </span>
                      <span style={s.uploadSub}>PNG, JPG, WebP — max 5MB</span>
                    </div>
                  )}
                </div>
                <input
                  ref={fileRef}
                  type="file"
                  accept="image/*"
                  style={{ display: "none" }}
                  onChange={handleImage}
                />
                {uploading && (
                  <div style={s.progressWrap}>
                    <div style={{ ...s.progressBar, width: `${uploadProgress}%` }} />
                    <span style={s.progressLabel}>Uploading {uploadProgress}%</span>
                  </div>
                )}
              </div>

              {/* Content */}
              <div style={s.field}>
                <label style={s.label}>
                  Content <span style={s.req}>*</span>
                  <span style={s.charCount}>{form.content.length} chars</span>
                </label>
                <textarea
                  style={{ ...inputStyle("content"), ...s.textarea }}
                  placeholder="Share your ideas, insights, and stories with the world…"
                  value={form.content}
                  onChange={(e) => set("content", e.target.value)}
                  rows={8}
                />
                {errors.content && <span style={s.error}>{errors.content}</span>}
              </div>

              {/* Actions */}
              <div style={s.actions}>
                <button
                  style={{ ...s.publishBtn, opacity: publishing ? 0.7 : 1 }}
                  onClick={handlePublish}
                  disabled={publishing}
                  onMouseEnter={(e) => !publishing && (e.currentTarget.style.background = "#1e40af")}
                  onMouseLeave={(e) => !publishing && (e.currentTarget.style.background = "var(--blue)")}
                >
                  {publishing ? (
                    <><span style={s.spinner} /> {uploading ? `Uploading ${uploadProgress}%…` : "Publishing…"}</>
                  ) : (
                    "🚀 Publish Post"
                  )}
                </button>
                <button
                  style={s.cancelBtn}
                  onClick={onClose}
                  onMouseEnter={(e) => { e.currentTarget.style.background = "var(--bg-2)"; }}
                  onMouseLeave={(e) => { e.currentTarget.style.background = "transparent"; }}
                >
                  Cancel
                </button>
              </div>
            </div>
          </>
        ) : (
          /* Success */
          <div style={s.success}>
            <div style={s.successIcon}>🎉</div>
            <h2 style={s.successTitle}>Published!</h2>
            <p style={s.successSub}>Your post is live and visible to all readers in real-time.</p>
            <div style={s.successProgress} />
          </div>
        )}
      </div>
    </div>
  );
}

const s = {
  backdrop: {
    position: "fixed", inset: 0, zIndex: 200,
    background: "rgba(12,12,20,0.55)",
    backdropFilter: "blur(10px)",
    display: "flex", alignItems: "center", justifyContent: "center",
    padding: 24,
  },
  modal: {
    background: "#fff", borderRadius: "var(--radius-lg)",
    width: "100%", maxWidth: 660,
    padding: "40px 44px",
    maxHeight: "92vh", overflowY: "auto",
    position: "relative",
    animation: "slideDown 0.3s ease",
  },
  closeBtn: {
    position: "absolute", top: 18, right: 18,
    width: 36, height: 36, borderRadius: "50%",
    background: "var(--bg)", border: "1px solid var(--border)",
    fontSize: "0.95rem", cursor: "pointer",
    display: "flex", alignItems: "center", justifyContent: "center",
    fontFamily: "var(--font-display)",
  },
  header: {
    display: "flex", alignItems: "center", gap: 16, marginBottom: 28,
  },
  headerIcon: {
    width: 52, height: 52, borderRadius: 14,
    background: "var(--bg-2)", fontSize: "1.6rem",
    display: "flex", alignItems: "center", justifyContent: "center",
    flexShrink: 0,
  },
  title: {
    fontSize: "1.5rem", fontWeight: 800, fontFamily: "var(--font-display)",
    color: "var(--ink)", letterSpacing: "-0.5px",
  },
  subtitle: { fontSize: "0.85rem", color: "var(--mid)", marginTop: 4 },
  form: { display: "flex", flexDirection: "column", gap: 20 },
  field: { display: "flex", flexDirection: "column", gap: 6 },
  label: {
    fontSize: "0.82rem", fontWeight: 700,
    fontFamily: "var(--font-display)", color: "var(--ink)",
    display: "flex", alignItems: "center", gap: 4,
  },
  labelSub: { fontWeight: 400, color: "var(--muted)", fontSize: "0.78rem" },
  req: { color: "var(--red)" },
  charCount: { marginLeft: "auto", color: "var(--muted)", fontWeight: 400, fontSize: "0.75rem" },
  row: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 },
  input: {
    padding: "11px 14px", border: "1.5px solid var(--border)",
    borderRadius: "var(--radius-sm)",
    fontFamily: "var(--font-body)", fontSize: "0.92rem",
    color: "var(--ink)", background: "var(--bg)",
    outline: "none", transition: "border 0.2s",
    width: "100%",
  },
  select: {
    padding: "11px 14px", border: "1.5px solid var(--border)",
    borderRadius: "var(--radius-sm)",
    fontFamily: "var(--font-body)", fontSize: "0.92rem",
    color: "var(--ink)", background: "var(--bg)",
    outline: "none", width: "100%", cursor: "pointer",
  },
  textarea: { resize: "vertical", minHeight: 160, lineHeight: 1.7 },
  uploadZone: {
    border: "2px dashed var(--border)", borderRadius: "var(--radius)",
    cursor: "pointer", transition: "all 0.2s", overflow: "hidden",
    minHeight: 120,
  },
  uploadPlaceholder: {
    display: "flex", flexDirection: "column", alignItems: "center",
    justifyContent: "center", gap: 8, padding: "28px 20px",
  },
  uploadText: {
    fontSize: "0.88rem", fontWeight: 600, color: "var(--mid)",
    fontFamily: "var(--font-display)",
  },
  uploadSub: { fontSize: "0.76rem", color: "var(--muted)" },
  previewWrap: { position: "relative" },
  preview: { width: "100%", height: 180, objectFit: "cover", display: "block" },
  removeImg: {
    position: "absolute", top: 8, right: 8,
    background: "rgba(12,12,20,0.7)", color: "#fff",
    border: "none", borderRadius: 6, padding: "4px 10px",
    fontSize: "0.8rem", cursor: "pointer", fontFamily: "var(--font-display)",
  },
  progressWrap: { marginTop: 8, position: "relative" },
  progressBar: {
    height: 4, background: "var(--blue)",
    borderRadius: 2, transition: "width 0.2s",
  },
  progressLabel: { fontSize: "0.75rem", color: "var(--blue)", marginTop: 4, display: "block" },
  error: { fontSize: "0.78rem", color: "var(--red)", fontFamily: "var(--font-display)" },
  actions: { display: "flex", gap: 12, marginTop: 4 },
  publishBtn: {
    flex: 1, padding: "13px 24px", background: "var(--blue)",
    color: "#fff", border: "none", borderRadius: "var(--radius-sm)",
    fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "0.95rem",
    cursor: "pointer", transition: "background 0.2s",
    display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
  },
  cancelBtn: {
    padding: "13px 24px", background: "transparent",
    color: "var(--mid)", border: "1.5px solid var(--border)",
    borderRadius: "var(--radius-sm)",
    fontFamily: "var(--font-display)", fontWeight: 600, fontSize: "0.92rem",
    cursor: "pointer", transition: "background 0.2s",
  },
  spinner: {
    width: 16, height: 16, border: "2px solid rgba(255,255,255,0.3)",
    borderTopColor: "#fff", borderRadius: "50%",
    animation: "spin 0.7s linear infinite", display: "inline-block",
  },
  success: {
    display: "flex", flexDirection: "column", alignItems: "center",
    justifyContent: "center", padding: "40px 20px", gap: 16, textAlign: "center",
  },
  successIcon: { fontSize: "3.5rem", animation: "fadeUp 0.4s ease" },
  successTitle: {
    fontSize: "1.8rem", fontWeight: 800, fontFamily: "var(--font-display)",
    animation: "fadeUp 0.4s 0.1s ease both",
  },
  successSub: { color: "var(--mid)", animation: "fadeUp 0.4s 0.2s ease both" },
  successProgress: {
    width: "100%", height: 3, background: "var(--border)",
    borderRadius: 2, overflow: "hidden", marginTop: 16,
    position: "relative",
  },
};
